import{c as e,Q as a,j as d,m as r}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Claude Code 我用了半年，才发现一个很离谱的点：上下文什么时候烧满，我是完全没感觉的。","description":"","frontmatter":{"title":"Claude Code 我用了半年，才发现一个很离谱的点：上下文什么时候烧满，我是完全没感觉的。","author":"sitin（@sitinme）","date":"2026-03-26T00:00:00.000Z","source":"https://x.com/sitinme/status/2037075581058056298","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-26-@sitinme-056298.md","filePath":"research/tweets/2026-03-26-@sitinme-056298.md","lastUpdated":1779898417000}'),o={name:"research/tweets/2026-03-26-@sitinme-056298.md"};function l(n,t,i,s,u,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="claude-code-我用了半年-才发现一个很离谱的点-上下文什么时候烧满-我是完全没感觉的。" tabindex="-1">Claude Code 我用了半年，才发现一个很离谱的点：上下文什么时候烧满，我是完全没感觉的。 <a class="header-anchor" href="#claude-code-我用了半年-才发现一个很离谱的点-上下文什么时候烧满-我是完全没感觉的。" aria-label="Permalink to &quot;Claude Code 我用了半年，才发现一个很离谱的点：上下文什么时候烧满，我是完全没感觉的。&quot;">​</a></h1><p>最开始我还以为是模型抽风——写着写着突然变笨，前面说好的逻辑 — @sitinme</p><p><strong>來源</strong>：<a href="https://x.com/sitinme/status/2037075581058056298" target="_blank" rel="noreferrer">https://x.com/sitinme/status/2037075581058056298</a><strong>作者</strong>：sitin（@sitinme） <strong>發布日期</strong>：2026-03-26 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：推文 <strong>統計</strong>：555 likes · 91 retweets · 833 bookmarks · 69,810 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Claude Code 我用了半年，才发现一个很离谱的点：上下文什么时候烧满，我是完全没感觉的。</p><p>最开始我还以为是模型抽风——写着写着突然变笨，前面说好的逻辑不认了，甚至开始自相矛盾。后来才反应过来：不是它变傻了，是上下文早就爆了。</p><p>最近发现一个叫 Claude HUD 的插件，干的事特别简单——在终端底部加一行状态栏，实时显示上下文占用百分比、当前用的什么模型、工具在调什么、子 Agent 跑到哪了。就一行信息，但装上之后真的回不去了。</p><p>安装就三步，在 Claude Code 里敲： <code>/plugin marketplace add jarrodwatts/claude-hud</code> + <code>plugin install claude-hud/claude-hud:setup</code></p><p>重启就能用。 我觉得这个插件最值钱的就是那个上下文进度条。它读的是 Claude Code 原生的 token 数据，不是估算的，颜色会从绿变黄变红。</p><p>绿色就放心用，黄色该注意了，红色就得考虑压缩或者开新会话。到了 85% 以上还会自动展开明细，告诉你输入输出各用了多少 token，钱到底花在哪了。</p><p>说实话，这个东西解决的不是什么高深的技术问题，它解决的是信息差。AI 工具现在能力都很强，真正卡效率的反而是你跟工具之间的信息不对称——它知道自己在干什么，你不知道。</p><p>上下文悄悄满了你没察觉，子 Agent 跑偏了你没看见，token 烧了多少心里没数。这些事单个都不大，但积少成多，整个开发体验就变得不可控了。</p><p>Claude HUD 就是把这层窗户纸捅破了，该看到的信息都摆在眼前，你随时能判断是继续推进、压缩上下文、还是干脆开个新会话。</p><p>好的工具不只是帮你干活，还得让你清楚它在干什么，这才是用起来真正踏实的状态。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude HUD 插件在終端底部加一行狀態欄，實時顯示 context 占用百分比（綠→黃→紅）、模型、工具呼叫和子 Agent 狀態，解決用戶與 AI 工具間的資訊不對稱問題。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>半年使用 Claude Code 才發現 context 燒滿完全無感，以為模型變笨其實是 context 爆了</li><li>真正卡效率的不是 AI 能力，而是用戶和工具之間的「資訊不對稱」——AI 知道自己在幹什麼，用戶不知道</li><li>Claude HUD 讀取 Claude Code 原生 token 數據（非估算），顏色分級：綠→放心用、黃→注意、紅→壓縮或開新 session</li><li>85% 以上自動展開明細：input/output 各用多少 token，錢花在哪裡</li><li>好工具不只幫你幹活，還要讓你清楚它在幹什麼</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Claude HUD：github jarrodwatts/claude-hud</li><li>安裝：<code>/plugin marketplace add jarrodwatts/claude-hud</code> + <code>plugin install claude-hud/claude-hud:setup</code>，重啟生效</li><li>85% 閾值自動展開 token 明細</li><li>讀取原生 token 數據，非估算</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>推文非常簡短，核心觀點是「資訊差解決」，技術細節少</li><li>Claude HUD 功能簡單但解決了真實痛點：本 workspace 的 context-management.md 規則需要 /usage 手動查，而 HUD 自動化了這個監控</li><li>只解決「可見性」問題，不解決「管理」問題——知道要壓縮不等於 Claude 自動壓縮</li><li>與 context-management.md 的 70% 通知機制重疊，但 HUD 更即時且可視化</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>可立即安裝使用；但 cc-workspace 已有 /usage 指令，HUD 是錦上添花</td></tr><tr><td>B. 創新性 (20%)</td><td>5/10</td><td>解決已知問題的簡單工具，「資訊不對稱」框架有一定洞見</td></tr><tr><td>C. 證據品質 (20%)</td><td>6/10</td><td>第一手半年使用感受，無量化數據</td></tr><tr><td>D. 技術深度 (15%)</td><td>4/10</td><td>技術細節極少，僅描述功能和安裝方式</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>所有 Claude Code 用戶都適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>5.90/10</strong></td><td></td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：功能簡單，與現有 context-management.md 規則重疊，加權總分 5.9 未達整合門檻。可在需要時作為推薦工具提及。</p>',28)])])}const m=e(o,[["render",l]]);export{p as __pageData,m as default};
